import{_ as e,o,c as i,ai as r}from"./chunks/framework.BH_J6TYN.js";const h=JSON.parse('{"title":"Glosario","description":"Términos de SYNTIweb explicados en simple","frontmatter":{"title":"Glosario","description":"Términos de SYNTIweb explicados en simple"},"headers":[],"relativePath":"shared/glosario.md","filePath":"shared/glosario.md"}'),n={name:"shared/glosario.md"};function t(d,a,s,l,c,p){return o(),i("div",null,[...a[0]||(a[0]=[r('<h2 id="ref" tabindex="-1">REF <a class="header-anchor" href="#ref" aria-label="Permalink to &quot;REF&quot;">​</a></h2><p>La moneda que usa SYNTIweb para mostrar precios. REF significa &quot;referencia dólar&quot;. Es el precio en dólares americanos de tu producto o servicio. REF 15 = $15 USD.</p><h2 id="blueprint" tabindex="-1">Blueprint <a class="header-anchor" href="#blueprint" aria-label="Permalink to &quot;Blueprint&quot;">​</a></h2><p>El tipo de página de tu negocio. Hay tres: <strong>Studio</strong> (página completa), <strong>Food</strong> (menú digital) y <strong>Cat</strong> (catálogo con carrito).</p><h2 id="panel-de-administracion" tabindex="-1">Panel de administración <a class="header-anchor" href="#panel-de-administracion" aria-label="Permalink to &quot;Panel de administración&quot;">​</a></h2><p>El lugar donde editas todo tu negocio. Se accede con PIN desde el celular o computadora. Es invisible para tus clientes — solo tú lo ves.</p><h2 id="pin" tabindex="-1">PIN <a class="header-anchor" href="#pin" aria-label="Permalink to &quot;PIN&quot;">​</a></h2><p>Tu contraseña de 4 dígitos para entrar al panel. Lo defines tú cuando creas tu cuenta. Se puede cambiar desde <strong>Configuración → PIN de Acceso</strong>.</p><h2 id="qr" tabindex="-1">QR <a class="header-anchor" href="#qr" aria-label="Permalink to &quot;QR&quot;">​</a></h2><p>El código cuadrado que tus clientes escanean con el celular para ver tu página. SYNTIweb lo genera automáticamente y lo puedes descargar para imprimir.</p><h2 id="subdominio" tabindex="-1">Subdominio <a class="header-anchor" href="#subdominio" aria-label="Permalink to &quot;Subdominio&quot;">​</a></h2><p>La dirección de tu página: <code>tunegocio.syntiweb.com</code>. El &quot;tunegocio&quot; es el subdominio. Se elige una vez y no se puede cambiar.</p><h2 id="tasa-bcv" tabindex="-1">Tasa BCV <a class="header-anchor" href="#tasa-bcv" aria-label="Permalink to &quot;Tasa BCV&quot;">​</a></h2><p>El precio oficial del dólar según el Banco Central de Venezuela. SYNTIweb lo usa para convertir tus precios REF a bolívares automáticamente. Se actualiza cada día.</p><h2 id="tenant" tabindex="-1">Tenant <a class="header-anchor" href="#tenant" aria-label="Permalink to &quot;Tenant&quot;">​</a></h2><p>Término interno para cada negocio en SYNTIweb. Cada tenant tiene su propia página, contenido y configuración, aislado de los demás negocios.</p><h2 id="whatsapp-checkout" tabindex="-1">WhatsApp Checkout <a class="header-anchor" href="#whatsapp-checkout" aria-label="Permalink to &quot;WhatsApp Checkout&quot;">​</a></h2><p>Cuando un cliente hace un pedido y SYNTIweb construye el mensaje automáticamente para enviar por WhatsApp. El cliente solo toca &quot;Enviar&quot;.</p><h2 id="pedido-rapido" tabindex="-1">Pedido Rápido <a class="header-anchor" href="#pedido-rapido" aria-label="Permalink to &quot;Pedido Rápido&quot;">​</a></h2><p>Función de SYNTIfood (plan Anual) que permite al cliente tocar [+] en cada plato, acumular su pedido y enviarlo como mensaje de WhatsApp.</p><h2 id="mini-order-sc-xxxx" tabindex="-1">Mini Order / SC-XXXX <a class="header-anchor" href="#mini-order-sc-xxxx" aria-label="Permalink to &quot;Mini Order / SC-XXXX&quot;">​</a></h2><p>Código de seguimiento de SYNTIcat (plan Anual). Cada pedido recibe un código único como SC-0001, SC-0042, etc. Viaja en el mensaje de WhatsApp.</p><h2 id="medios-de-pago" tabindex="-1">Medios de pago <a class="header-anchor" href="#medios-de-pago" aria-label="Permalink to &quot;Medios de pago&quot;">​</a></h2><p>Chips informativos que aparecen en tu página mostrando qué métodos de pago aceptas. <strong>No son pasarela de pago</strong> — solo información visual para tus clientes.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/referencia/glosario.html">Glosario completo</a> — Todos los términos técnicos con más detalle</li><li><a href="/shared/faq.html">Preguntas frecuentes</a> — Dudas comunes resueltas</li><li><a href="/shared/moneda-y-precios.html">Moneda y precios</a> — Cómo funciona el REF y la tasa BCV</li></ul>',26)])])}const m=e(n,[["render",t]]);export{h as __pageData,m as default};
